import "@radix-ui/themes/styles.css";
import { Card, AspectRatio, Text, Link, Flex, Heading } from "@radix-ui/themes";
import './App.css';
import ProjectsCard from "./ProjectsCard";

const Projects = (props) => {
    return (
        <Link>
            <Card>
                <Flex direction="row" gap="1rem" style={{padding: "2rem"}}>
                    <Flex ratio={16 / 9} style={{width: "30%"}} align="start">
                        <AspectRatio ratio={16 / 9}>
                            <img src="/evesubsystemanalysis.png" alt="Project 1" style={{ border: "1px solid white;", borderRadius: "5px", width: "100%", objectFit: "cover" }} />
                        </AspectRatio>
                    </Flex>
                    <Flex direction="column" align="start" width="70%">
                        <Link mb="2" size="5" weight="medium">Eve Subsystem Analysis</Link>
                        <Text size="4" weight="light" style={{color: "rgba(255, 255, 255, 0.73)"}}>The most comprehensive tool on the web for analysing the subsystem market in Eve Online. View trade volume, market orders, real-time price data, and recent losses.</Text>
                    </Flex>
                </Flex>
            </Card>
        </Link>
    );
};

export default Projects;
